{
    "hooks": {
        "SessionStart": [
            {
                "matcher": "",
                "hooks": [{"type": "command", "command": "entire hooks claude-code session-start"}],
            }
        ],
        "SessionEnd": [
            {
                "matcher": "",
                "hooks": [{"type": "command", "command": "entire hooks claude-code session-end"}],
            }
        ],
        "UserPromptSubmit": [
            {
                "matcher": "",
                "hooks": [
                    {"type": "command", "command": "entire hooks claude-code user-prompt-submit"}
                ],
            }
        ],
        "Stop": [
            {
                "matcher": "",
                "hooks": [{"type": "command", "command": "entire hooks claude-code stop"}],
            }
        ],
        "PreToolUse": [
            {
                "matcher": "Edit|Write",
                "hooks": [
                    {
                        "type": "command",
                        "command": "python3 $CLAUDE_PROJECT_DIR/.claude/hooks/block-hardcoded-secrets.py",
                    }
                ],
            },
            {
                "matcher": "Bash",
                "hooks": [
                    {
                        "type": "command",
                        "command": "python3 $CLAUDE_PROJECT_DIR/.claude/hooks/block-bare-secret-exports.py",
                    }
                ],
            },
            {
                "matcher": "Task",
                "hooks": [{"type": "command", "command": "entire hooks claude-code pre-task"}],
            },
        ],
        "PostToolUse": [
            {
                "matcher": "Edit|Write",
                "hooks": [
                    {
                        "type": "command",
                        "command": 'jq -r \'.tool_input.file_path\' | while read file_path; do if [[ "$file_path" =~ \\.py$ ]]; then ruff check --fix "$file_path" \u0026\u0026 ruff format "$file_path"; fi; done',
                    }
                ],
            },
            {
                "matcher": "Task",
                "hooks": [{"type": "command", "command": "entire hooks claude-code post-task"}],
            },
            {
                "matcher": "TodoWrite",
                "hooks": [{"type": "command", "command": "entire hooks claude-code post-todo"}],
            },
        ],
    },
    "permissions": {"deny": ["Read(./.entire/metadata/**)"]},
}

